# ━━━ UTF-8 强制模式（防止 Windows GBK 编码崩溃 + 抑制 OpenCV 噪音）━━━
os.environ.setdefault("PYTHONIOENCODING", "utf-8")
os.environ.setdefault("PYTHONUTF8", "1")
os.environ.setdefault("OPENCV_LOG_LEVEL", "ERROR")      # 抑制 OpenCV C++ 层 obsensor 报错
