# ==================== SSL 兼容层（国密证书 / 自签证书 / 网络波动） ====================

def _requests_get_ssl_fallback(url: str, **kwargs) -> requests.Response:
    """带 SSL 回退的 requests.get()。

    中国部分政府网站（*.gov.cn 等）使用国密（SM2/SM9）证书，
    Python 标准 OpenSSL 无法验证，导致 SSL: BAD_ECPOINT 错误。
    此函数先尝试正常 SSL 验证，失败时自动回退到 verify=False。

    同时处理 TLS 握手超时（部分防火墙干扰）和连接重置。
    """
    try:
        return requests.get(url, **kwargs)
    except requests.exceptions.SSLError:
        import warnings
        try:
            import urllib3
            urllib3.disable_warnings(urllib3.exceptions.InsecureRequestWarning)
        except Exception:
            pass
        warnings.filterwarnings("ignore", message="Unverified HTTPS request")
        # 移除可能传入的 verify 参数，强制关闭验证
        kwargs.pop("verify", None)
        return requests.get(url, verify=False, **kwargs)


# ==================== 通用下载工具（进度条 + 超时 + 断点续传） ====================

def _download_file(url: str, dest: str, timeout: float = 120.0,
                   resume: bool = True, show_progress: bool = True,
                   chunk_size: int = 256 * 1024) -> bool:
    """下载文件，带进度条、超时、断点续传。

    Args:
        url: 下载地址
        dest: 目标文件路径
        timeout: 总超时秒数（默认 120s，足够下载 ~50MB 文件）
        resume: 是否启用断点续传（HTTP Range）
        show_progress: 是否显示进度条
        chunk_size: 块大小（默认 256KB，减少循环次数）
    Returns:
        True 表示下载成功
    """
    downloaded = 0
    file_mode = 'ab' if resume else 'wb'
    existing_size = os.path.getsize(dest) if (resume and os.path.exists(dest)) else 0

    # 构建请求头
    headers = {}
    if resume and existing_size > 0:
        headers['Range'] = f'bytes={existing_size}-'

    start_time = time.time()
    last_print = start_time

    try:
        # 使用 requests 库（已在顶部导入），自动处理 SSL、重定向、连接复用
        # stream=True + 自定义超时避免 hang
        resp = requests.get(url, headers=headers, stream=True,
                           timeout=(10, timeout))  # (connect_timeout, read_timeout)
        resp.raise_for_status()

        # 服务器忽略了 Range 请求 → 返回完整文件，不能追加到已有部分
        if resume and existing_size > 0 and resp.status_code != 206:
            existing_size = 0
            downloaded = 0
            file_mode = 'wb'

        total_size = existing_size
        content_range = resp.headers.get('Content-Range', '')
        content_length = resp.headers.get('Content-Length')

        if content_range:
            # 服务器支持 Range → 断点续传生效
            total_size = int(content_range.split('/')[-1])
            downloaded = existing_size
        elif content_length:
            total_size = existing_size + int(content_length)

        # 磁盘空间预检（避免下载到一半失败）
        if total_size > 0:
            try:
                import shutil as _shutil
                free = _shutil.disk_usage(os.path.dirname(dest) or '.').free
                needed = total_size - existing_size
                if free < needed + 50 * 1024 * 1024:  # 留 50MB 余量
                    print(f"   ⚠️ 磁盘空间不足（需要 {needed/1024/1024:.0f}MB，可用 {free/1024/1024:.0f}MB）")
                    return False
            except Exception:
                pass  # disk_usage 失败不阻塞

        with open(dest, file_mode) as f:
            for chunk in resp.iter_content(chunk_size=chunk_size):
                if not chunk:
                    continue
                f.write(chunk)
                downloaded += len(chunk)

                # 进度显示（最多每秒刷新一次，避免刷屏）
                now = time.time()
                if show_progress and (now - last_print > 0.5 or downloaded >= total_size > 0):
                    last_print = now
                    elapsed = now - start_time
                    speed = downloaded / elapsed if elapsed > 0 else 0
                    if total_size > 0:
                        pct = downloaded * 100 / total_size
                        eta = (total_size - downloaded) / speed if speed > 0 else 0
                        bar_len = 25
                        filled = int(bar_len * downloaded / total_size)
                        bar = '█' * filled + '░' * (bar_len - filled)
                        # 使用 \r 原地刷新
                        print(f"\r   ⬇ {bar} {pct:5.1f}% | "
                              f"{_fmt_size(downloaded)}/{_fmt_size(total_size)} | "
                              f"{_fmt_speed(speed)} | ETA {_fmt_time(eta)}  ",
                              end='', flush=True)
                    else:
                        print(f"\r   ⬇ 已下载 {_fmt_size(downloaded)} | {_fmt_speed(speed)}  ",
                              end='', flush=True)

        if show_progress:
            elapsed = time.time() - start_time
            avg_speed = downloaded / elapsed if elapsed > 0 else 0
            print(f"\r   ✅ 下载完成！{_fmt_size(downloaded)} 用时 {_fmt_time(elapsed)} "
                  f"({_fmt_speed(avg_speed)})   ")
        return True

    except requests.exceptions.Timeout:
        print(f"\n   ⚠️ 下载超时（{timeout}秒），请检查网络")
        return False
    except requests.exceptions.ConnectionError:
        print(f"\n   ⚠️ 无法连接服务器，请检查网络")
        return False
    except Exception as e:
        print(f"\n   ⚠️ 下载失败：{e}")
        return False


def _fmt_size(size: float) -> str:
    """格式化文件大小"""
    for unit in ('B', 'KB', 'MB', 'GB'):
        if abs(size) < 1024.0:
            return f"{size:.1f}{unit}"
        size /= 1024.0
    return f"{size:.1f}TB"


def _fmt_speed(speed: float) -> str:
    """格式化下载速度"""
    return _fmt_size(speed) + "/s"


def _fmt_time(seconds: float) -> str:
    """格式化时间"""
    if seconds < 60:
        return f"{seconds:.0f}s"
    elif seconds < 3600:
        m, s = divmod(int(seconds), 60)
        return f"{m}m{s}s"
    else:
        h, r = divmod(int(seconds), 3600)
        m, s = divmod(r, 60)
        return f"{h}h{m}m"


# ==================== Python 版本自适配 ====================
# 无论用户用什么 Python 版本启动本程序，自动找到最合适的版本来运行。
# 太旧 (<3.10) → 找系统上 3.10-3.13 的版本重新启动
# 太新 (>3.13) → 部分 C 扩展可能尚无 wheel，同样找兼容版本
# 找不到 → 自动下载嵌入版 Python 3.12
_AUTO_RELAUNCH_DONE = os.environ.get("_JARVIS_RELAUNCHED", "")
_COMPAT_MIN = (3, 10)
_COMPAT_MAX = (3, 13)
_CURRENT_VER = sys.version_info[:2]

if not _AUTO_RELAUNCH_DONE:
    _too_old = _CURRENT_VER < _COMPAT_MIN
    _too_new = _CURRENT_VER > _COMPAT_MAX

    if _too_old or _too_new:
        _reason = "太旧" if _too_old else f"太新（>{_COMPAT_MAX[0]}.{_COMPAT_MAX[1]}，C 扩展可能无 wheel）"
        print(f"⚠️ 当前 Python {sys.version.split()[0]} {_reason}")
        print(f"   推荐 {_COMPAT_MIN[0]}.{_COMPAT_MIN[1]}-{_COMPAT_MAX[0]}.{_COMPAT_MAX[1]}，正在搜索系统上的合适版本…")

        _best_py = None
        _py_launcher = shutil.which("py")
        if _py_launcher:
            try:
                _r = subprocess.run([_py_launcher, "-0"], capture_output=True,
                                    text=True, timeout=5)
                _candidates = []
                for line in _r.stdout.split('\n'):
                    m = re.search(r'(\d+)\.(\d+)', line)
                    if m:
                        _maj, _min = int(m.group(1)), int(m.group(2))
                        if _COMPAT_MIN <= (_maj, _min) <= _COMPAT_MAX:
                            _candidates.append(((_maj, _min), f"python{_maj}.{_min}"))
                _candidates.sort(key=lambda x: (-x[0][0], -x[0][1]))  # 版本降序
                for (_ver, _name) in _candidates:
                    _p = shutil.which(_name)
                    if _p and os.path.exists(_p):
                        _best_py = _p
                        break
            except Exception:
                pass

        if _best_py and os.path.abspath(_best_py) != os.path.abspath(sys.executable):
            print(f"   🔄 找到 Python {_best_py}，重新启动…\n")
            os.environ["_JARVIS_RELAUNCHED"] = "1"
            os.execv(_best_py, [_best_py, __file__] + sys.argv[1:])

        # 没找到合适版本 → 自动下载嵌入版（幂等，已安装则秒过）
        print("   未在系统上找到合适版本 → 自动下载 Python 3.12 嵌入版…")
        _embed_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), ".python")
        _embed_exe = os.path.join(_embed_dir, "python.exe")
        if not os.path.exists(_embed_exe):
            try:
                _COMPAT_VER = "3.12.10"
                _machine = platform.machine().lower()
                if _machine in ("amd64", "x86_64"):
                    _arch = "amd64"
                elif _machine in ("arm64", "aarch64"):
                    _arch = "arm64"
                else:
                    _arch = "win32"
                _mirror = ("https://registry.npmmirror.com/-/binary/python/"
                           f"{_COMPAT_VER}/python-{_COMPAT_VER}-embed-{_arch}.zip")
                _tmp_zip = os.path.join(tempfile.gettempdir(),
                                        f"python-{_COMPAT_VER}-embed.zip")
                _get_pip = os.path.join(tempfile.gettempdir(), "get-pip.py")

                # 并行下载 Python 嵌入版 zip + get-pip.py
                print(f"   ⬇ 并行下载 Python {_COMPAT_VER} 嵌入版 + pip…")
                _futures = []
                with ThreadPoolExecutor(max_workers=2) as _pool:
                    _futures.append(_pool.submit(
                        _download_file, _mirror, _tmp_zip, 120, True, True))
                    _futures.append(_pool.submit(
                        _download_file,
                        "https://bootstrap.pypa.io/get-pip.py",
                        _get_pip, 30, False, False))
                    _ok_zip = _futures[0].result()
                    _ok_pip = _futures[1].result()

                if not _ok_zip:
                    raise RuntimeError("Python embed download failed")
                if not _ok_pip:
                    print(f"   ⚠️ get-pip.py 下载失败，pip 可能不可用")

                # 解压
                import zipfile as _zf
                os.makedirs(_embed_dir, exist_ok=True)
                print(f"   📦 解压中…")
                with _zf.ZipFile(_tmp_zip, 'r') as _z:
                    _z.extractall(_embed_dir)
                try:
                    os.remove(_tmp_zip)
                except Exception:
                    pass

                # 启用 pip（修改 _pth 文件）
                _pth = os.path.join(_embed_dir, "python312._pth")
                if os.path.exists(_pth):
                    with open(_pth, 'r', encoding='utf-8') as f:
                        _content = f.read()
                    _content = _content.replace("#import site", "import site")
                    if "Lib/site-packages" not in _content:
                        _content += "\nLib/site-packages\n"
                    with open(_pth, 'w', encoding='utf-8') as f:
                        f.write(_content)

                # 安装 pip（已并行下载好 get-pip.py）
                os.makedirs(os.path.join(_embed_dir, "Lib", "site-packages"), exist_ok=True)
                print(f"   📦 安装 pip（清华镜像加速）…")
                _result = subprocess.run(
                    [_embed_exe, _get_pip, "--no-setuptools", "--no-wheel",
                     "-i", "https://pypi.tuna.tsinghua.edu.cn/simple"],
                    capture_output=True, text=True, timeout=120,
                )
                try:
                    os.remove(_get_pip)
                except Exception:
                    pass
                if _result.returncode != 0:
                    _err_tail = _result.stderr.strip()[-200:] if _result.stderr else ""
                    print(f"   ⚠️ pip 安装警告：{_err_tail}")

                # 持久化 pip 镜像配置
                try:
                    _pip_ini = os.path.join(_embed_dir, "pip.ini")
                    with open(_pip_ini, 'w', encoding='utf-8') as f:
                        f.write("[global]\n"
                                "index-url = https://pypi.tuna.tsinghua.edu.cn/simple\n"
                                "trusted-host = pypi.tuna.tsinghua.edu.cn\n")
                except Exception:
                    pass

                print(f"   ✅ Python {_COMPAT_VER} 嵌入版安装完成")
            except Exception as _e:
                print(f"   ⚠️ 自动安装失败：{_e}")
                _embed_exe = None

        if _embed_exe and os.path.exists(_embed_exe):
            print(f"   🔄 切换到嵌入版 Python 3.12 重新启动…\n")
            os.environ["_JARVIS_RELAUNCHED"] = "1"
            os.execv(_embed_exe, [_embed_exe, __file__] + sys.argv[1:])

        print(f"   ⚠️ 未能获取合适版本，继续使用当前 Python（可能有兼容性问题）\n")

