# ==================== 云端 API 提供商系统 ====================

@dataclass
class CloudProvider:
    """云端 AI 提供商配置"""
    name: str                           # 显示名称，如 "DeepSeek"
    slug: str                           # CLI 标识符，如 "deepseek"
    api_url: str                        # Chat Completions 端点完整 URL
    api_key_env: str                    # API Key 环境变量名
    default_api_key: str = ""           # 硬编码备用 Key（可选）
    default_model: str = ""             # 默认模型
    available_models: List[str] = field(default_factory=list)  # 可选模型列表
    max_output_tokens: int = 8192       # 模型实际能输出的最大 token 数（超过会被截断）
    supports_vision: bool = False       # 是否支持图片/多模态输入
    vision_model: str = ""              # 视觉专用模型（空=用 default_model）
    supports_image_gen: bool = False    # 是否支持图片生成
    image_gen_model: str = ""           # 图片生成专用模型
    reasoning_model: str = ""           # 推理专用模型（数学/代码/逻辑，空=不自动切换）
    supports_video_gen: bool = False    # 是否支持视频生成
    video_gen_model: str = ""           # 视频生成专用模型


@dataclass
class TaskIntent:
    """从用户输入解析出的任务意图 — 用于后续完成度评估。

    🔴 设计原则：验证不依赖 AI 的"声称"，而是直接对照用户需求检查系统事实。
    """
    summary: str = ""                       # 一句话总结用户要什么
    # ━━━ 操作类型（决定验证方式）━━━
    action_type: str = "unknown"            # create/delete/move/copy/install/uninstall/open/close/query/unknown
    # ━━━ 创建类：期望存在的文件 ━━━
    expected_files: List[str] = field(default_factory=list)  # 期望产出的文件名
    expected_extensions: List[str] = field(default_factory=list)  # 期望产出的文件扩展名（无具体文件名时）
    # ━━━ 删除/移动类：需要验证的目标 ━━━
    delete_targets: List[str] = field(default_factory=list)    # 用户要求删除的文件/文件夹（路径或名称）
    move_sources: List[str] = field(default_factory=list)      # 移动操作的源路径
    move_destinations: List[str] = field(default_factory=list) # 移动操作的目标路径
    # ━━━ 安装类 ━━━
    install_targets: List[str] = field(default_factory=list)   # 用户要求安装的软件名
    # ━━━ 进程类 ━━━
    processes_to_start: List[str] = field(default_factory=list)  # 需要启动的进程名
    processes_to_stop: List[str] = field(default_factory=list)   # 需要停止的进程名
    # ━━━ 最终验证条件（由 _analyze_task_intent 填充，_assess_completion 逐项检查）━━━
    expected_absent: List[str] = field(default_factory=list)   # 完成后必须不存在的路径
    expected_present: List[str] = field(default_factory=list)  # 完成后必须存在的路径（含内容>0）
    # ━━━ 桌面操作 ━━━
    is_desktop_action: bool = False         # 是否为桌面操作任务（切歌/打开窗口/输入文字等）
    is_media_action: bool = False           # 是否为媒体控制任务（切歌/暂停/音量等）
    # ━━━ 工具约束 ━━━
    required_tools: List[str] = field(default_factory=list)  # 🔴 必须使用的工具名列表（任一个匹配即可）
    forbidden_tools: List[str] = field(default_factory=list) # 🔴 禁止使用的工具（如用 desktop_icons_count 冒充 arrange）


@dataclass
class CompletionResult:
    """统一的任务完成度评估结果。

    🔴 设计原则：硬证据（文件存在/不存在、进程状态）= is_done=False；
       软证据（AI 措辞问题）= reasons 但 is_done 仍为 True。
    """
    is_done: bool = False                   # 默认未完成——只有正面证据能证明完成
    reasons: List[str] = field(default_factory=list)  # 诊断信息（不一定触发重试）
    missing_files: List[str] = field(default_factory=list)  # 应存在但缺失的文件（硬证据）
    undeleted_items: List[str] = field(default_factory=list)  # 应删除但仍存在的项目（硬证据）
    has_errors: bool = False                # AI 回复中是否包含错误信息（硬证据）


