def _get_available_cloud_providers() -> Dict[str, CloudProvider]:
    """返回已配置 API Key 的提供商（含硬编码 key、环境变量 key、Agnes Token Plan key）"""
    available: Dict[str, CloudProvider] = {}
    for slug, p in DEFAULT_CLOUD_PROVIDERS.items():
        key = _resolve_api_key(p)
        if key:
            available[slug] = p
    return available


def _resolve_api_key(provider: CloudProvider) -> str:
    """解析提供商的 API Key，Agnes 优先使用 Token Plan 的付费 Key。

    Agnes Token Plan 购买后会获得一个新的 API Key（cpk-...），
    存放在 AGNES_TOKEN_PLAN 环境变量中。该 Key 需要实际发送到
    Agnes API 服务器才能按付费计划计费——仅在本地检测是不够的。
    """
    if provider.slug == "agnes":
        plan_token = os.getenv("AGNES_TOKEN_PLAN", "").strip()
        if plan_token:
            return plan_token
    return os.getenv(provider.api_key_env, provider.default_api_key)


def _apply_agnes_token_plan(provider: CloudProvider) -> None:
    """检测 Agnes Token Plan 并提升提供商的输出上限。

    购买 Token Plan 后设置 AGNES_TOKEN_PLAN 环境变量，
    即可解锁 16384 输出、图像生成、视频生成等 Pro 功能。
    必须在 set_backend() 之前调用，否则 compact_mode 判断会出错。
    """
    if provider.slug == "agnes":
        provider.max_output_tokens = 4096  # 先重置为默认值
        plan_token = os.getenv("AGNES_TOKEN_PLAN", "").strip()
        if plan_token:
            provider.max_output_tokens = 16384


def _get_process_for_file(ext_or_name: str) -> Optional[str]:
    """根据文件扩展名或程序名返回对应的进程名，用于进程启动验证。

    覆盖所有场景——媒体/文档/工程/脚本/服务器——不局限于特定文件类型。
    贾维斯的原则：任何文件/程序启动后都应该能找到对应的进程。
    """
    ext = ext_or_name.lower().lstrip('.')
    # 如果已经是一个已知进程名（无扩展名），直接返回
    _KNOWN_PROCESSES = {
        # 运行时 / 脚本引擎
        'python', 'python3', 'pythonw', 'node', 'ruby', 'perl', 'php',
        'java', 'javaw', 'dotnet', 'msbuild', 'cargo', 'rustc', 'go',
        # 包管理器
        'npm', 'npx', 'yarn', 'pnpm', 'pip', 'pip3', 'winget', 'choco', 'scoop',
        # 数据库 / 服务器
        'nginx', 'apache', 'httpd', 'mysql', 'mysqld', 'mariadb', 'postgres',
        'redis', 'redis-server', 'mongod', 'mongos', 'sqlserver',
        # 容器 / 虚拟化
        'docker', 'dockerd', 'containerd', 'podman', 'kubectl', 'vagrant',
        # 开发工具
        'git', 'cmake', 'make', 'gradle', 'maven', 'ant', 'nuget',
        'msiexec', 'installer', 'setup',
        # 编辑器 / IDE
        'code', 'notepad++', 'vim', 'nvim', 'sublime_text', 'idea64',
        # 终端 / Shell
        'cmd', 'powershell', 'pwsh', 'bash', 'wsl', 'conhost',
        'windowsterminal', 'terminal',
    }
    if ext in _KNOWN_PROCESSES:
        return ext

    # 扩展名 → 关联进程
    _EXT_MAP = {
        # 媒体
        'png': 'photos', 'jpg': 'photos', 'jpeg': 'photos',
        'gif': 'photos', 'bmp': 'photos', 'webp': 'photos',
        'svg': 'msedge', 'ico': 'photos',
        'mp4': 'videoplayer', 'avi': 'videoplayer', 'mov': 'videoplayer',
        'mkv': 'videoplayer', 'wmv': 'videoplayer', 'webm': 'videoplayer',
        'mp3': 'musicplayer', 'wav': 'musicplayer', 'flac': 'musicplayer',
        'ogg': 'musicplayer', 'm4a': 'musicplayer',
        # 文档
        'pdf': 'msedge',
        'docx': 'winword', 'doc': 'winword', 'rtf': 'winword',
        'xlsx': 'excel', 'xls': 'excel', 'csv': 'excel',
        'pptx': 'powerpnt', 'ppt': 'powerpnt',
        'txt': 'notepad', 'md': 'notepad', 'log': 'notepad',
        'html': 'msedge', 'htm': 'msedge', 'url': 'msedge',
        # 工程 / 脚本
        'py': 'python', 'pyw': 'pythonw',
        'js': 'node', 'mjs': 'node', 'cjs': 'node',
        'ts': 'node', 'tsx': 'node', 'jsx': 'node',
        'rb': 'ruby',
        'php': 'php',
        'java': 'java', 'jar': 'javaw', 'class': 'java',
        'cs': 'dotnet', 'csproj': 'dotnet', 'sln': 'dotnet',
        'rs': 'cargo', 'go': 'go',
        'bat': 'cmd', 'cmd': 'cmd', 'ps1': 'powershell',
        'sh': 'bash',
        # 编译产物 / 可执行
        'exe': None,  # .exe 自身就是进程名，由调用方处理
        'dll': None,
        'msi': 'msiexec',
        # 压缩
        'zip': 'explorer', 'rar': 'explorer', '7z': 'explorer', 'tar': 'explorer',
    }
    return _EXT_MAP.get(ext)


def _infer_process_from_target(target: str, related_paths: List[str] = None) -> Optional[str]:
    """从关闭/停止目标推断对应的进程名，用于复合操作（关闭+删除）的进程验证。

    target: 用户要关闭的目标（可能是文件名、通用词如"图片"、或进程名）
    related_paths: 关联的文件路径列表（如 delete_targets），用于从扩展名推断进程

    优先级：
    1. target 本身是已知进程名 → 直接返回
    2. target 有扩展名 → 用 _get_process_for_file 映射
    3. target 是通用词（图片/视频/文档）→ 从 related_paths 的扩展名推断
    4. 无法推断 → 返回 None（不误报）
    """
    if not target:
        return None

    target_lower = target.lower().strip()

    # 1. 直接是已知进程名
    direct = _get_process_for_file(target_lower)
    if direct:
        return direct

    # 2. 有扩展名 → 用扩展名映射
    ext = os.path.splitext(target_lower)[1].lstrip('.')
    if ext:
        proc = _get_process_for_file(ext)
        if proc:
            return proc

    # 3. 通用词 → 从关联路径推断
    # "图片" → 查 related_paths 中是否有 .png/.jpg 等 → 映射到 photos
    # "视频" → 查 .mp4/.avi 等 → 映射到 videoplayer
    # "文档" → 查 .docx/.pdf 等
    _GENERIC_TO_CATEGORY = {
        '图片': ['png', 'jpg', 'jpeg', 'gif', 'bmp', 'webp', 'ico', 'tiff', 'svg'],
        '照片': ['png', 'jpg', 'jpeg', 'gif', 'bmp', 'webp', 'ico'],
        '视频': ['mp4', 'avi', 'mov', 'mkv', 'wmv', 'webm', 'flv'],
        '音乐': ['mp3', 'wav', 'flac', 'ogg', 'm4a', 'aac'],
        '文档': ['docx', 'doc', 'pdf', 'txt', 'md', 'rtf'],
        '表格': ['xlsx', 'xls', 'csv'],
    }
    # 也支持英文和常见简称
    _GENERIC_ALIASES = {
        'image': '图片', 'picture': '图片', 'photo': '照片', 'pic': '图片',
        'video': '视频', 'movie': '视频', 'clip': '视频',
        'music': '音乐', 'audio': '音乐', 'song': '音乐',
        'document': '文档', 'doc': '文档', 'file': '文档',
        'spreadsheet': '表格', 'sheet': '表格', 'table': '表格',
    }
    category = _GENERIC_TO_CATEGORY.get(target_lower)
    if not category:
        canonical = _GENERIC_ALIASES.get(target_lower)
        if canonical:
            category = _GENERIC_TO_CATEGORY.get(canonical)

    if category and related_paths:
        for path in related_paths:
            path_ext = os.path.splitext(str(path))[1].lower().lstrip('.')
            if path_ext in category:
                proc = _get_process_for_file(path_ext)
                if proc:
                    return proc
        # 如果关联路径没有匹配的扩展名，但有同类文件，
        # 用类别中第一个扩展名对应的进程作为默认值
        for cat_ext in category:
            proc = _get_process_for_file(cat_ext)
            if proc:
                return proc

    # 4. target 可能是进程名的一部分（模糊匹配已知进程）
    _COMMON_PROCESS_NAMES = {
        'photos': 'photos', 'photo': 'photos', '照片': 'photos',
        '画图': 'mspaint', 'mspaint': 'mspaint', 'paint': 'mspaint',
        '截图': 'snippingtool', 'snippingtool': 'snippingtool',
        'edge': 'msedge', 'msedge': 'msedge', '浏览器': 'msedge',
        'chrome': 'chrome', 'google': 'chrome',
        'notepad': 'notepad', '记事本': 'notepad',
        'explorer': 'explorer', '资源管理器': 'explorer',
        'vscode': 'code', 'code': 'code',
        'word': 'winword', 'winword': 'winword',
        'excel': 'excel',
        'powerpoint': 'powerpnt', 'ppt': 'powerpnt',
        '播放器': 'videoplayer', '播放': 'videoplayer',
        '音乐': 'musicplayer',
    }
    for key, proc in _COMMON_PROCESS_NAMES.items():
        if key in target_lower:
            return proc

    return None

# ==================== 工具函数 ====================

def get_program_dir() -> str:
    """返回程序所在目录（兼容 PyInstaller 打包为 exe 后运行）"""
    if getattr(sys, 'frozen', False):
        return os.path.dirname(os.path.abspath(sys.executable))
    return os.path.dirname(os.path.abspath(__file__))


def get_temp_dir() -> str:
    """返回临时文件目录（程序目录下 .jarvis_temp/），不存在则自动创建"""
    d = os.path.join(get_program_dir(), ".jarvis_temp")
    os.makedirs(d, exist_ok=True)
    return d


def _get_python_for_pip() -> Optional[str]:
    """返回最适合 pip install 的 Python 解释器。

    自动选择当前系统上包兼容性最好的版本：
    ① 已自动安装的兼容 Python（嵌入版）→  直接用
    ② 当前 Python 版本合适（3.8-3.12）→  直接用
    ③ 搜索系统上最好的 Python（3.10-3.12 优先）→  用最优的
    ④ 全找不到 →  自动安装嵌入版
    """
    if getattr(sys, 'frozen', False):
        for name in ['python', 'python3', 'py']:
            path = shutil.which(name)
            if path:
                try:
                    if os.path.abspath(path) != os.path.abspath(sys.executable):
                        return path
                except Exception:
                    return path
        return None

    # ① 已有自动安装的兼容 Python → 直接用它
    compat = _get_compat_python_path()
    if compat and os.path.exists(compat):
        return compat

    # ② 当前 Python 版本合适 → 直接用
    if (3, 8) <= sys.version_info[:2] <= (3, 12):
        return sys.executable

    # ③ 当前版本太新（≥3.13）或太旧（<3.8）→ 搜索系统上最合适的
    best = _find_best_python()
    if best:
        return best

    # ④ 找不到 → 自动安装嵌入版（3.12.10，轮子最全）
    installed = _auto_install_compat_python()
    if installed:
        return installed

    return sys.executable  # 最后兜底


def _get_compat_python_path() -> Optional[str]:
    """返回程序自带兼容 Python 的路径（.python/python.exe）"""
    return os.path.join(get_program_dir(), ".python", "python.exe")


def _find_best_python() -> Optional[str]:
    """在系统上搜索所有 Python，返回包兼容性最好的版本（3.10-3.12）。"""
    candidates = []

    # ━━━ Windows py 启动器（最可靠）━━━
    py_launcher = shutil.which("py")
    if py_launcher:
        try:
            result = subprocess.run(
                [py_launcher, "-0"], capture_output=True, text=True, timeout=5,
            )
            for line in result.stdout.split('\n'):
                m = re.search(r'(\d+)\.(\d+)', line)
                if m:
                    major, minor = int(m.group(1)), int(m.group(2))
                    exe = f"python{major}.{minor}"
                    path = shutil.which(exe) or shutil.which(f"python{major}{minor}")
                    if not path:
                        # 尝试常见安装路径
                        common = [
                            f"C:\\Python{major}{minor}\\python.exe",
                            f"C:\\Program Files\\Python{major}{minor}\\python.exe",
                            os.path.expanduser(f"~\\AppData\\Local\\Programs\\Python\\Python{major}{minor}\\python.exe"),
                        ]
                        for p in common:
                            if os.path.exists(p):
                                path = p
                                break
                    if path and os.path.exists(path):
                        candidates.append(((major, minor), path))
        except Exception:
            pass

    # ━━━ 扫描常见目录 ━━━
    if not candidates:
        for major in range(8, 15):
            for minor in range(0, 15):
                common = [
                    f"C:\\Python{major}{minor}\\python.exe",
                    f"C:\\Program Files\\Python{major}{minor}\\python.exe",
                    os.path.expanduser(f"~\\AppData\\Local\\Programs\\Python\\Python{major}{minor}\\python.exe"),
                ]
                for p in common:
                    if os.path.exists(p):
                        candidates.append(((major, minor), p))

    # ━━━ 排序：3.10-3.12 优先（兼容性最好），然后按版本降序 ━━━
    def _rank(ver_path):
        ver, _ = ver_path
        major, minor = ver
        if (3, 10) <= ver <= (3, 12):
            return (0, -major, -minor)  # 优先组，版本高的在前
        return (1, -major, -minor)      # 其他组

    candidates.sort(key=_rank)
    return candidates[0][1] if candidates else None


def _auto_install_compat_python() -> Optional[str]:
    """自动安装 Python 3.12（嵌入式版，~10MB，无需管理员权限）。
    安装到程序目录下的 .python/ 中，不影响系统 Python。
    返回 python.exe 路径，失败返回 None。"""
    import zipfile

    COMPAT_VER = "3.12.10"
    prog_dir = get_program_dir()
    install_dir = os.path.join(prog_dir, ".python")
    python_exe = os.path.join(install_dir, "python.exe")

    # 已安装 → 直接返回
    if os.path.exists(python_exe):
        return python_exe

    if not check_network(timeout=1.5):
        return None

    print(f"  [Python] 系统仅有 Python {sys.version_info.major}.{sys.version_info.minor}，"
          f"正在自动安装 Python {COMPAT_VER}（包兼容性最好）…")

    try:
        # 下载 embeddable 版本（体积小，无需安装）
        _machine = platform.machine().lower()
        if _machine in ("amd64", "x86_64"):
            arch = "amd64"
        elif _machine in ("arm64", "aarch64"):
            arch = "arm64"
        else:
            arch = "win32"
        url = (f"https://registry.npmmirror.com/-/binary/python/"
               f"{COMPAT_VER}/python-{COMPAT_VER}-embed-{arch}.zip")

        tmp_zip = os.path.join(tempfile.gettempdir(), f"python-{COMPAT_VER}-embed.zip")
        get_pip_path = os.path.join(tempfile.gettempdir(), "get-pip.py")

        # ---- parallel download: Python embed zip + get-pip.py ----
        print(f"  [Python] parallel download...")
        with ThreadPoolExecutor(max_workers=2) as pool:
            fut_zip = pool.submit(_download_file, url, tmp_zip, 120, True, True)
            fut_pip = pool.submit(_download_file,
                                  "https://bootstrap.pypa.io/get-pip.py",
                                  get_pip_path, 30, False, False)
            ok_zip = fut_zip.result()
            ok_pip = fut_pip.result()

        if not ok_zip:
            raise RuntimeError("Python embed download failed")
        if not ok_pip:
            print(f"  [Python] ⚠️ get-pip.py 下载失败，pip 可能不可用")

        # 解压
        os.makedirs(install_dir, exist_ok=True)
        with zipfile.ZipFile(tmp_zip, "r") as zf:
            zf.extractall(install_dir)
        try:
            os.remove(tmp_zip)
        except Exception:
            pass

        # 启用 pip：embeddable 版默认禁用，需修改 python3xx._pth 文件
        ver_parts = COMPAT_VER.split(".")
        pth_name = f"python{ver_parts[0]}{ver_parts[1]}._pth"
        pth_file = os.path.join(install_dir, pth_name)
        if os.path.exists(pth_file):
            with open(pth_file, "r", encoding="utf-8") as f:
                pth_content = f.read()
            pth_content = pth_content.replace("#import site", "import site")
            if "Lib/site-packages" not in pth_content:
                pth_content += "\nLib/site-packages\n"
            with open(pth_file, "w", encoding="utf-8") as f:
                f.write(pth_content)

        # 安装 pip（get-pip.py 已并行下载好 + 清华镜像加速）
        print(f"  [Python] installing pip (tsinghua mirror)...")
        os.makedirs(os.path.join(install_dir, "Lib", "site-packages"), exist_ok=True)
        result = subprocess.run(
            [python_exe, get_pip_path, "--no-setuptools", "--no-wheel",
             "-i", "https://pypi.tuna.tsinghua.edu.cn/simple"],
            capture_output=True, text=True, timeout=120,
        )
        try:
            os.remove(get_pip_path)
        except Exception:
            pass
        if result.returncode != 0:
            err_tail = result.stderr.strip()[-200:] if result.stderr else ""
            print(f"  [Python] pip install failed: {err_tail}")

        # 配置 pip 默认使用清华镜像（持久化，后续 pip install 无需重复指定）
        try:
            pip_ini = os.path.join(install_dir, "pip.ini")
            with open(pip_ini, "w", encoding="utf-8") as f:
                f.write("[global]\n")
                f.write("index-url = https://pypi.tuna.tsinghua.edu.cn/simple\n")
                f.write("trusted-host = pypi.tuna.tsinghua.edu.cn\n")
        except Exception:
            pass  # pip.ini 写入失败不影响使用（_run_pip_install 有 -i 兜底）

        # 验证
        result = subprocess.run(
            [python_exe, "-c", "import pip; print('pip OK')"],
            capture_output=True, text=True, timeout=15,
        )
        if result.returncode == 0:
            print(f"  [Python] ✅ Python {COMPAT_VER} + pip 安装完成 → {install_dir}")
            return python_exe
        else:
            print(f"  [Python] ⚠️ 安装完成但 pip 不可用")
            return python_exe  # 还是返回，能做基本 Python 执行

    except Exception as e:
        print(f"  [Python] ⚠️ 自动安装失败：{e}")

    return None


def check_network(timeout: float = 1.5) -> bool:
    """检测网络是否可达（并行探测 DNS + HTTPS 兜底）"""
    targets = [("8.8.8.8", 53), ("1.1.1.1", 53), ("114.114.114.114", 53)]

    def _try_connect(host: str, port: int) -> bool:
        s = None
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(timeout)
            s.connect((host, port))
            return True
        except Exception:
            return False
        finally:
            if s:
                s.close()

    # 并行探测所有 DNS 目标
    with ThreadPoolExecutor(max_workers=3) as executor:
        futures = {executor.submit(_try_connect, h, p): (h, p) for h, p in targets}
        for future in as_completed(futures):
            if future.result():
                return True

    # 兜底：HTTP 请求
    try:
        requests.get("https://www.baidu.com", timeout=timeout)
        return True
    except Exception:
        return False


# ---- IP 属地检测（缓存结果，避免重复请求）----
_is_china_ip: Optional[bool] = None


def is_china_ip(timeout: float = 3.0) -> bool:
    """检测当前 IP 是否在中国境内（结果缓存，首次调用后不再联网）。
    用于搜索时自动适配：国内用户优先国内源，海外用户保留国际源。
    """
    global _is_china_ip
    if _is_china_ip is not None:
        return _is_china_ip

    # 多个服务依次尝试（国内用 myip.ipip.net，海外用 ip-api.com）
    services = [
        # 服务1：ipip.net（国内直连快，返回中文"中国"）
        lambda: _check_ip_via_ipip(timeout),
        # 服务2：ip-api.com（国际通用，免费无需 key）
        lambda: _check_ip_via_ipapi(timeout),
        # 服务3：ip.sb（全球可用）
        lambda: _check_ip_via_ipsb(timeout),
    ]
    for svc in services:
        try:
            result = svc()
            if result is not None:
                _is_china_ip = result
                return result
        except Exception:
            continue

    # 全失败 → 保守假设在国内，但不缓存（下次调用可能网络恢复）
    # 不设置 _is_china_ip，避免永久缓存错误结果
    return True


def _check_ip_via_ipip(timeout: float) -> Optional[bool]:
    """通过 myip.ipip.net 检测（国内最稳定）"""
    try:
        r = requests.get("http://myip.ipip.net", timeout=timeout)
        r.encoding = "utf-8"
        # 返回格式："当前 IP：x.x.x.x  来自于：中国 上海 上海"
        return "中国" in r.text
    except Exception:
        return None


def _check_ip_via_ipapi(timeout: float) -> Optional[bool]:
    """通过 ip-api.com 检测（国际通用）"""
    try:
        r = requests.get("http://ip-api.com/json/", timeout=timeout)
        data = r.json()
        return data.get("countryCode") == "CN"
    except Exception:
        return None


def _check_ip_via_ipsb(timeout: float) -> Optional[bool]:
    """通过 api.ip.sb 检测"""
    try:
        r = requests.get("https://api.ip.sb/geoip", timeout=timeout)
        data = r.json()
        return data.get("country_code") == "CN"
    except Exception:
        return None


def _read_file_auto_encoding(filepath: str) -> str:
    """智能编码读取文件：自动检测 UTF-8 / GBK / UTF-8-BOM 等编码。
    中文 Windows 上大量 .txt 文件是 GBK 编码，硬编码 UTF-8 会导致乱码。
    策略：UTF-8 → GBK → GB2312 → latin-1，选中文可读性最好的。"""
    # 先读原始字节
    with open(filepath, "rb") as f:
        raw = f.read()

    if not raw:
        return ""

    # 候选编码列表（中文 Windows 上最常见的优先）
    candidates = ["utf-8", "gbk", "gb2312", "utf-8-sig", "latin-1"]

    def _score(text: str) -> int:
        """评分：中文字符越多、�越少 = 分数越高"""
        replacement = text.count('�')  # Unicode 替换字符 �
        cjk = len(re.findall(r'[一-鿿]', text))
        # 中文多且替换字符少 = 高分
        return cjk * 10 - replacement * 100

    best_text = None
    best_score = -999999

    for enc in candidates:
        try:
            text = raw.decode(enc)
            score = _score(text)
            if score > best_score:
                best_score = score
                best_text = text
        except (UnicodeDecodeError, LookupError):
            continue

    return best_text if best_text is not None else raw.decode("utf-8", errors="replace")


def _extract_file_paths(text: str) -> list:
    """从用户输入中提取真实存在的文件路径。
    解决 split() 无法处理的情况：
    - 路径含空格：\"C:\\path\\my file.txt\" → 引号内空格不拆分
    - 路径粘连文字：C:\\a.txt完成任务 → 按扩展名截断
    - 混合：用户可能混用引号路径 + 无引号路径
    """
    results = []
    FILE_EXTS = {'.txt', '.py', '.js', '.ts', '.tsx', '.jsx', '.html', '.css',
                 '.json', '.md', '.yml', '.yaml', '.xml', '.csv', '.pdf', '.docx',
                 '.ps1', '.bat', '.cmd', '.sh', '.java', '.c', '.cpp', '.h',
                 '.png', '.jpg', '.jpeg', '.gif', '.webp', '.bmp', '.mp4', '.avi',
                 '.mov', '.mkv', '.webm', '.mp3', '.wav', '.m4a', '.ogg', '.flac'}

    # 方法1：引号路径（双引号或单引号）
    for m in re.finditer(r'["\']([^"\']+?\.[a-zA-Z0-9]+)["\']', text):
        path = m.group(1).strip()
        if os.path.exists(path):
            results.append(path)

    # 方法2：无引号路径 — 匹配常见模式
    # Windows: C:\...\file.ext  或  \\...\file.ext
    for m in re.finditer(r'[A-Za-z]:[\\/][^\s,;，；。]+?\.[a-zA-Z0-9]+', text):
        path = m.group(0).strip()
        if os.path.exists(path):
            results.append(path)

    # 方法3：粘连文字 → 尝试从匹配到的路径截断
    # 如 "C:\a.txt按要求完成" → 找到 "C:\a.txt" 部分
    for m in re.finditer(r'[A-Za-z]:[\\/][^\s,;，；。]+', text):
        candidate = m.group(0).strip()
        # 从末尾开始，逐个字符缩短，找到存在的文件
        for ext in sorted(FILE_EXTS, key=len, reverse=True):
            pos = candidate.lower().find(ext)
            if pos > 0:
                path = candidate[:pos + len(ext)]
                if os.path.exists(path) and path not in results:
                    results.append(path)
                    break

    # 去重
    seen = set()
    unique = []
    for p in results:
        if p.lower() not in seen:
            seen.add(p.lower())
            unique.append(p)
    return unique


# 记录上一次 _run_pip_install 使用的 Python 路径（与当前进程不同时需要 sys.path 桥接）
_pip_python_path: Optional[str] = None


def _run_pip_install(packages: list, timeout: int = 120) -> bool:
    """pip install 包装。自动选择最佳 Python + 国内镜像。
    通过全局 _pip_python_path 记录实际安装所用的 Python 路径。
    """
    global _pip_python_path
    _pip_python_path = None

    python_exe = _get_python_for_pip()
    if python_exe is None:
        return False

    # 国内用户自动使用清华镜像加速
    mirror_args = []
    if is_china_ip():
        mirror_args = ["-i", "https://pypi.tuna.tsinghua.edu.cn/simple",
                       "--trusted-host", "pypi.tuna.tsinghua.edu.cn"]

    def _try_install(py_exe: str) -> bool:
        try:
            result = subprocess.run(
                [py_exe, "-m", "pip", "install"] + mirror_args + packages,
                capture_output=True, text=True, timeout=timeout,
                encoding="utf-8", errors="replace",
            )
            if result.returncode != 0:
                err = result.stderr.strip() or result.stdout.strip()
                if err:
                    err_lines = err.split('\n')
                    tail = '\n'.join(err_lines[-5:])
                    print(f"   pip install 失败：{tail}")
                return False
            return True
        except subprocess.TimeoutExpired:
            print(f"   pip install 超时（{timeout}秒）")
            return False
        except Exception as e:
            print(f"   pip install 异常：{e}")
            return False

    # ① 用最佳 Python 安装
    if _try_install(python_exe):
        _pip_python_path = os.path.abspath(python_exe)
        return True

    # ② 失败 → 回退到嵌入版 Python（如果还没试过）
    compat = _get_compat_python_path()
    if compat and os.path.exists(compat) and os.path.abspath(compat) != os.path.abspath(python_exe):
        if not _ensure_compat_pip(compat):
            return False
        if _try_install(compat):
            _pip_python_path = os.path.abspath(compat)
            return True

    return False


def _ensure_compat_pip(compat_python: str) -> bool:
    """确保兼容 Python 已安装 pip（嵌入版默认不带 pip）"""
    try:
        result = subprocess.run(
            [compat_python, "-m", "pip", "--version"],
            capture_output=True, text=True, timeout=10,
        )
        if result.returncode == 0:
            return True
    except Exception:
        pass
    # pip 不可用 → 触发重新安装，之后重新验证 pip
    _auto_install_compat_python()
    try:
        result = subprocess.run(
            [compat_python, "-m", "pip", "--version"],
            capture_output=True, text=True, timeout=10,
        )
        return result.returncode == 0
    except Exception:
        return False


def _try_import_after_pip(import_name: str):
    """pip install 成功后尝试导入包。
    如果安装 Python ≠ 当前进程 Python（_pip_python_path 已设置），
    则自动将该 Python 的 site-packages 加入 sys.path 再试（纯 Python 包可桥接）。
    返回 (module, is_bridged: bool)；导入失败抛出 ImportError。
    """
    try:
        return __import__(import_name), False
    except ImportError:
        pip_py = _pip_python_path
        if not pip_py or os.path.abspath(pip_py) == os.path.abspath(sys.executable):
            raise  # 同一个 Python，不是桥接问题
        # 安装 Python ≠ 当前进程 → 将其 site-packages 注入当前进程搜索路径
        # 纯 Python 包（.py）可在任意版本间共享；C 扩展包（.pyd）版本不匹配会失败
        site_pkg = os.path.join(os.path.dirname(pip_py), "Lib", "site-packages")
        if not os.path.isdir(site_pkg):
            raise
        if site_pkg not in sys.path:
            sys.path.insert(0, site_pkg)
        try:
            mod = __import__(import_name)
            return mod, True
        except ImportError:
            if site_pkg in sys.path:
                sys.path.remove(site_pkg)
            raise


# ==================== 统一 pip 依赖安装框架 ====================
# 所有可选 pip 依赖的注册表 — 添加新依赖只需在此加一项，无需写函数

@dataclass
class _PipDep:
    """一个可选 pip 依赖的完整描述"""
    key: str                                    # 唯一标识符
    packages: List[str]                         # pip install 包名列表
    import_names: List[str]                     # import 模块名（与 packages 一一对应）
    desc: str                                   # 中文功能描述
    flag_names: List[str] = field(default_factory=list)   # 全局 _HAS_XXX 标志名
    mod_names: List[str] = field(default_factory=list)    # 全局模块变量名
    attrs: List[str] = field(default_factory=list)       # 从模块提取的属性名（空=整个模块）
    extra_note: str = ""                        # 安装前额外提示
    pip_timeout: int = 120                      # pip 安装超时秒数

