        self._backend_forced: bool = False    # 用户通过 --backend 显式指定后端，跳过菜单
        self._last_reply_text: str = ""
        self._last_undo_meta: dict = {}    # 最近一次撤销快照的元数据（msg_count 等）
        self._temp_files: List[str] = []  # launch_and_watch 创建的临时 .ps1，程序退出时清理
        self._generated_files: List[str] = []  # 本轮交互中 AI 工具生成的文件（截图/图片/视频/TTS 等）
        self._desktop_safety_net_triggered: bool = False  # 安全网：AI 没输出桌面代码块时自动执行了默认操作
        self._desktop_fallback_count: int = 0  # 安全网执行了多少个键盘回退（>0 表示回退链已跑完，不需重试）
        self._last_major_task: str = ""  # 最近一次非继续类的主要任务（用于跨轮次需求追踪）
        self._ai_lock = threading.Lock()  # 语音线程与文本线程的 AI 交互互斥锁
        self._voice_mode_lock = threading.Lock()  # 电话模式互斥锁
        self._in_voice_conversation: bool = False  # 是否正在电话对话中
        self._voice_messages: List[dict] = []  # 语音模式独立的对话上下文（与 _messages 隔离）
        self._voice_threshold: float = 2.5  # 噪声倍数（越低越灵敏，范围 1.0~5.0）
        self._voice_min_threshold: float = 1000.0  # 绝对最低阈值（范围 10~2000，滤背景杂音兼顾灵敏度）
        self._in_repair: bool = False           # 修复进行中标志，阻止嵌套 SELF_REPAIR + 消息污染
        # ━━━ 自我进化：从失败中学习 ━━━
        self._failure_patterns: Dict[str, int] = {}  # 失败模式 → 出现次数
        self._learned_rules: List[str] = []           # 已固化的规则（注入系统提示词）
        self._evolution_threshold: int = 2            # 同一模式出现N次后固化为规则
        # Claude Code 信息窗（默认弹出可见窗口，用户可实时观看）
        self._claude_show_window: bool = True   # 默认显示信息窗，/claude quiet 关闭
